import React, { useEffect, useState, useCallback } from 'react';
import { Link } from 'react-router-dom';
import api from '../utils/api';
import Spinner from '../components/Spinner';
import Pagination from '../components/Pagination';

export default function Patients() {
  const [patients, setPatients] = useState([]);
  const [search, setSearch] = useState('');
  const [page, setPage] = useState(1);
  const [pages, setPages] = useState(1);
  const [total, setTotal] = useState(0);
  const [loading, setLoading] = useState(true);

  const fetchPatients = useCallback(async () => {
    setLoading(true);
    try {
      const res = await api.get('/users/patients', { params: { search, page, limit: 10 } });
      setPatients(res.data.patients);
      setPages(res.data.pages);
      setTotal(res.data.total);
    } finally {
      setLoading(false);
    }
  }, [search, page]);

  useEffect(() => { fetchPatients(); }, [fetchPatients]);

  return (
    <div>
      <div className="d-flex justify-content-between align-items-center mb-4">
        <h4 className="mb-0">Patients ({total})</h4>
        <Link to="/records/new" className="btn btn-primary btn-sm">
          <i className="bi bi-plus-lg me-1" />New Record
        </Link>
      </div>

      <div className="card mb-3">
        <div className="card-body">
          <input
            className="form-control"
            placeholder="Search by name, email or phone..."
            value={search}
            onChange={(e) => { setSearch(e.target.value); setPage(1); }}
          />
        </div>
      </div>

      {loading ? <Spinner /> : (
        <div className="card">
          <div className="card-body p-0">
            <table className="table table-hover mb-0">
              <thead className="table-light">
                <tr>
                  <th>Name</th>
                  <th>Email</th>
                  <th>Age</th>
                  <th>Gender</th>
                  <th>Phone</th>
                  <th>Blood Group</th>
                  <th>Actions</th>
                </tr>
              </thead>
              <tbody>
                {patients.length === 0 ? (
                  <tr><td colSpan={7} className="text-center text-muted py-3">No patients found</td></tr>
                ) : patients.map((p) => (
                  <tr key={p._id}>
                    <td>{p.name}</td>
                    <td>{p.email}</td>
                    <td>{p.age || '—'}</td>
                    <td>{p.gender || '—'}</td>
                    <td>{p.phone || '—'}</td>
                    <td>{p.bloodGroup || '—'}</td>
                    <td>
                      <Link to={`/records/new?patient=${p._id}`} className="btn btn-sm btn-outline-primary me-1" title="New Record">
                        <i className="bi bi-file-earmark-plus" />
                      </Link>
                      <Link to={`/records?patientId=${p._id}`} className="btn btn-sm btn-outline-secondary me-1" title="View Records">
                        <i className="bi bi-eye" />
                      </Link>
                      <Link to={`/timeline/${p._id}`} className="btn btn-sm btn-outline-info" title="Timeline">
                        <i className="bi bi-clock-history" />
                      </Link>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}
      <div className="mt-3">
        <Pagination page={page} pages={pages} onPageChange={setPage} />
      </div>
    </div>
  );
}
